 32→function ViewToggle({
 33→  selected,
 34→  onSelect,
 35→}: {
 36→  selected: ViewState;
 37→  onSelect: (v: ViewState) => void;
 38→}) {
 39→  const labels: Record<ViewState, string> = {
 40→    list: 'List (6)',
 41→    empty: 'Empty',
 42→    filtered: 'Filtered',
 43→  };
 44→
 45→  return (
 46→    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
 47→      {(['list', 'empty', 'filtered'] as const).map(v => (
 48→        <Pressable
 49→          key={v}
 50→          onPress={() => onSelect(v)}
 51→          style={{
 52→            paddingHorizontal: 16,
 53→            paddingVertical: 8,
 54→            borderRadius: 20,
 55→            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
 56→          }}
 57→        >
 58→          <Text
 59→            type="paragraphMDM"
 60→            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
 61→          >
 62→            {labels[v]}
 63→          </Text>
 64→        </Pressable>
 65→      ))}
 66→    </View>
 67→  );
 68→}
