 70→function VoucherListDemo() {
 71→  const [view, setView] = useState<ViewState>('list');
 72→  const screen = useSDUIJsonEditor(SCREENS[view]);
 73→
 74→  return (
 75→    <ScrollView style={{ flex: 1 }}>
 76→      <View style={{ padding: 24, maxWidth: 420 }}>
 77→        <Text type="headingMDL" mb="nano">
 78→          SDUI: Meus Vouchers
 79→        </Text>
 80→        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
 81→          Renders the voucher list from JSON via SDUI engine. Cards use context
 82→          interpolation — edit the JSON to change data dynamically.
 83→        </Text>
 84→
 85→        <ViewToggle selected={view} onSelect={setView} />
 86→
 87→        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
 88→          <ScreenRenderer screen={screen} />
 89→        </Box>
 90→      </View>
 91→    </ScrollView>
 92→  );
 93→}
