147→function SideBySideComparison() {
148→  const screen = useSDUIJsonEditor(voucherListLoaded);
149→
150→  return (
151→    <ScrollView style={{ flex: 1 }}>
152→      <View style={{ padding: 24 }}>
153→        <Text type="headingMDL" mb="nano">
154→          Side-by-Side: Real Screen vs SDUI
155→        </Text>
156→        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
157→          Left: traditional React components with hardcoded data. Right: same
158→          visual result rendered entirely from JSON via the SDUI engine.
159→        </Text>
160→
161→        <View style={{ flexDirection: 'row', gap: 24 }}>
162→          <View style={{ flex: 1, maxWidth: 420 }}>
163→            <Text type="subtitleXXL" mb="nano" align="center">
164→              Real Screen (SP_0004.6)
165→            </Text>
166→            <Box br="sm" style={{ overflow: 'hidden' }}>
167→              <RealScreenPreview />
168→            </Box>
169→          </View>
170→
171→          <View style={{ flex: 1, maxWidth: 420 }}>
172→            <Text type="subtitleXXL" mb="nano" align="center">
173→              SDUI from JSON
174→            </Text>
175→            <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
176→              <ScreenRenderer screen={screen} />
177→            </Box>
178→          </View>
179→        </View>
180→
181→        <SeparatorHorizontal mv="xs" />
182→
183→        <Box pd="innerSmall" bgColor="BRAND_COMPLEMENT_02" br="sm">
184→          <Text type="paragraphMDM" mb="xxxs">
185→            Key difference
186→          </Text>
187→          <Text type="bodyMD" color="INTENSE_COLOR_03">
188→            The left column requires code changes to update content. The right
189→            column renders from JSON — the backend can change card data, add new
190→            cards, or switch statuses without any frontend deploy.
191→          </Text>
192→        </Box>
193→      </View>
194→    </ScrollView>
195→  );
