  3→import type {
  4→  SDUIScreen,
  5→  SDUIComponent,
  6→  SDUIComponentRegistry,
  7→  SDUIComponentProps,
  8→  SDUIContext,
  9→  SDUIConditional,
 10→} from '../models';
 11→import { interpolateDeep } from '../utils/interpolation';
 12→import { evaluateRule } from '../utils/jsonLogic';
 13→import { getDefaultRegistry, getRenderer } from '../registry';
 14→import FallbackComponent from './FallbackComponent';
 15→
 16→interface ScreenRendererProps {
 17→  screen: SDUIScreen;
 18→  registry?: SDUIComponentRegistry;
 19→}
 20→
 21→function isConditional(value: unknown): value is SDUIConditional {
 22→  return (
 23→    value !== null &&
 24→    typeof value === 'object' &&
 25→    'rule' in (value as Record<string, unknown>) &&
 26→    typeof (value as Record<string, unknown>).rule === 'object'
 27→  );
 28→}
 29→
 30→function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
 31→  if (!component.visible) return true;
 32→  const { rule } = component.visible;
 33→  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
 34→    return true;
 35→  }
 36→  return evaluateRule(rule, context);
 37→}
 38→
 39→function separateConditionals(props: SDUIComponentProps): {
 40→  interpolatable: SDUIComponentProps;
 41→  conditionals: Record<string, SDUIConditional>;
 42→} {
 43→  const interpolatable: SDUIComponentProps = {};
 44→  const conditionals: Record<string, SDUIConditional> = {};
 45→
 46→  for (const key of Object.keys(props)) {
 47→    if (isConditional(props[key])) {
 48→      conditionals[key] = props[key] as SDUIConditional;
 49→    } else {
 50→      interpolatable[key] = props[key];
 51→    }
 52→  }
 53→
 54→  return { interpolatable, conditionals };
 55→}
 56→
 57→function renderComponent(
 58→  component: SDUIComponent,
 59→  context: SDUIContext,
 60→  registry: SDUIComponentRegistry,
 61→  key: string,
 62→) {
 63→  if (!isVisible(component, context)) return null;
 64→
 65→  const { interpolatable, conditionals } = separateConditionals(component.props);
 66→  const interpolatedProps = {
 67→    ...interpolateDeep(interpolatable, context),
 68→    ...conditionals,
 69→  };
 70→
 71→  const Renderer = getRenderer(registry, component.type);
 72→
 73→  if (!Renderer) {
 74→    return (
 75→      <FallbackComponent
 76→        key={key}
 77→        type={component.type}
 78→        props={interpolatedProps}
 79→      />
 80→    );
 81→  }
 82→
 83→  return <Renderer key={key} props={interpolatedProps} context={context} />;
 84→}
 85→
 86→export default function ScreenRenderer({
 87→  screen,
 88→  registry,
 89→}: ScreenRendererProps) {
 90→  const activeRegistry = registry ?? getDefaultRegistry();
 91→  const { context, header, body, footer } = screen;
 92→
 93→  return (
 94→    <View style={{ flex: 1 }}>
 95→      {header && renderComponent(header, context, activeRegistry, 'header')}
 96→
 97→      <View style={{ flex: 1 }}>
 98→        {(body ?? []).map((component, index) =>
 99→          renderComponent(
100→            component,
101→            context,
102→            activeRegistry,
103→            `${component.type}-${index}`,
104→          ),
105→        )}
106→      </View>
107→
108→      {footer && renderComponent(footer, context, activeRegistry, 'footer')}
109→    </View>
110→  );
111→}
